-- ============================================================================
-- BASELINE SQUASH — 2026-06-06
-- ============================================================================
-- Single squashed snapshot of the production schema (public + private) for
-- Supabase project flyingbluewhale (xrovijzjbyssajhtwvas), generated via
--   supabase db dump --linked -s public,private
--
-- WHY: the local migration files and the remote schema_migrations history had
-- diverged badly (MCP apply_migration auto-stamps its own version, so ~65
-- migrations were recorded under timestamps that did not match their local
-- filenames; ~8 migrations existed only on remote; local had duplicate version
-- numbers 0061-0064). Rather than reconcile 129 files row-by-row, the operator
-- chose to squash to this baseline on 2026-06-06.
--
-- The 129 pre-squash migration files (0001..0076 + timestamped) are preserved
-- in supabase/migrations.archive_20260606_squash/ for historical reference and
-- for SQL not re-emitted here (storage.* RLS policies, auth triggers — system
-- schemas were intentionally excluded from this app-schema dump).
--
-- The remote schema_migrations table was reset to a single row at this version.
-- Includes 0060_ssot_3nf_orphan_remediation (guide_comments CHECK + deprecation
-- comments), applied to remote immediately before this dump.
-- ============================================================================




SET statement_timeout = 0;
SET lock_timeout = 0;
SET idle_in_transaction_session_timeout = 0;
SET client_encoding = 'UTF8';
SET standard_conforming_strings = on;
SELECT pg_catalog.set_config('search_path', '', false);
SET check_function_bodies = false;
SET xmloption = content;
SET client_min_messages = warning;
SET row_security = off;


