CREATE OR REPLACE FUNCTION "private"."auth_org_ids"() RETURNS SETOF "uuid"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  return query select org_id from memberships where user_id = auth.uid();
end;
$$;


ALTER FUNCTION "private"."auth_org_ids"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "private"."auth_user_email"() RETURNS "text"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'auth'
    AS $$
declare
  v text;
begin
  select email from auth.users where id = auth.uid() into v;
  return v;
end;
$$;


ALTER FUNCTION "private"."auth_user_email"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "private"."budgets_compute_estimate"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
begin
  if new.quantity is not null and new.rate_cents is not null then
    new.estimate_cents := round(new.quantity * new.rate_cents);
  end if;
  return new;
end;
$$;


ALTER FUNCTION "private"."budgets_compute_estimate"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "private"."budgets_recompute_actual"("p_org_id" "uuid", "p_project_id" "uuid", "p_department" "text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
declare
  total_cents bigint;
begin
  if p_project_id is null or p_department is null then return; end if;

  select coalesce(sum(amount_cents), 0)
    into total_cents
    from public.expenses
   where org_id = p_org_id
     and project_id = p_project_id
     and department = p_department
     and status in ('approved', 'reimbursed');

  update public.budgets
     set actual_cents = total_cents,
         spent_cents = total_cents
   where org_id = p_org_id
     and project_id = p_project_id
     and department = p_department;
end;
$$;


ALTER FUNCTION "private"."budgets_recompute_actual"("p_org_id" "uuid", "p_project_id" "uuid", "p_department" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "private"."budgets_recompute_actual"("p_org_id" "uuid", "p_project_id" "uuid", "p_department" "text") IS 'Recompute budgets.actual_cents for a single (org, project, department) bucket from approved/reimbursed expenses.';



CREATE OR REPLACE FUNCTION "private"."effective_user_locale_settings"() RETURNS TABLE("locale" "text", "timezone" "text", "currency" "text")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with u as (
    select locale, timezone, currency
    from user_preferences where user_id = auth.uid()
  ),
  o as (
    select default_locale, default_timezone, default_currency
    from orgs
    where id in (select org_id from memberships where user_id = auth.uid())
    order by created_at asc
    limit 1
  )
  select
    coalesce((select locale from u),   (select default_locale from o),   'en')   as locale,
    coalesce((select timezone from u), (select default_timezone from o), 'UTC')  as timezone,
    coalesce((select currency from u), (select default_currency from o), 'USD')  as currency;
$$;


ALTER FUNCTION "private"."effective_user_locale_settings"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "private"."expenses_rollup_actual"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
begin
  if tg_op in ('UPDATE', 'DELETE') then
    if old.project_id is not null and old.department is not null then
      perform private.budgets_recompute_actual(old.org_id, old.project_id, old.department);
    end if;
  end if;

  if tg_op in ('INSERT', 'UPDATE') then
    if new.project_id is not null and new.department is not null then
      perform private.budgets_recompute_actual(new.org_id, new.project_id, new.department);
    end if;
  end if;

  return null;
end;
$$;


ALTER FUNCTION "private"."expenses_rollup_actual"() OWNER TO "postgres";


COMMENT ON FUNCTION "private"."expenses_rollup_actual"() IS 'XPMS Expenses → budgets.actual_cents rollup. Fires on every expense write; recomputes both old + new buckets so reassignments balance.';



CREATE OR REPLACE FUNCTION "private"."expenses_sync_receipt_state"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
begin
  if tg_op = 'INSERT' then
    if new.receipt_state is null and new.status is not null then
      new.receipt_state := new.status;
    elsif new.status is null and new.receipt_state is not null then
      new.status := new.receipt_state;
    end if;
  elsif tg_op = 'UPDATE' then
    -- If only one of the two changed in this update, mirror the change
    -- to the other. If both changed, prefer receipt_state as the
    -- canonical (post-LDP) value.
    if new.receipt_state is distinct from old.receipt_state then
      new.status := new.receipt_state;
    elsif new.status is distinct from old.status then
      new.receipt_state := new.status;
    end if;
  end if;
  return new;
end;
$$;


ALTER FUNCTION "private"."expenses_sync_receipt_state"() OWNER TO "postgres";


