CREATE OR REPLACE FUNCTION "private"."redact_audit_log_pii"("p_max_age_days" integer DEFAULT 90, "p_batch_size" integer DEFAULT 5000) RETURNS TABLE("redacted" integer, "cutoff" timestamp with time zone)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
declare
  v_cutoff timestamptz;
  v_redacted int;
begin
  v_cutoff := now() - (p_max_age_days || ' days')::interval;

  with target as (
    select id
      from public.audit_events
     where at < v_cutoff
       and actor_email is not null
       and pii_redacted_at is null
     limit p_batch_size
  )
  update public.audit_events e
     set actor_email = null,
         pii_redacted_at = now()
    from target
   where e.id = target.id;

  get diagnostics v_redacted = row_count;
  return query select v_redacted, v_cutoff;
end;
$$;


ALTER FUNCTION "private"."redact_audit_log_pii"("p_max_age_days" integer, "p_batch_size" integer) OWNER TO "postgres";


COMMENT ON FUNCTION "private"."redact_audit_log_pii"("p_max_age_days" integer, "p_batch_size" integer) IS 'Nulls audit_events.actor_email on rows older than p_max_age_days (default 90). Idempotent + batched. Returns (count, cutoff) for monitoring.';



