CREATE TABLE IF NOT EXISTS "public"."time_off_requests" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "org_id" "uuid" NOT NULL,
    "user_id" "uuid" NOT NULL,
    "policy_id" "uuid" NOT NULL,
    "starts_on" "date" NOT NULL,
    "ends_on" "date" NOT NULL,
    "hours_requested" numeric(8,2) NOT NULL,
    "reason" "text",
    "request_state" "text" DEFAULT 'pending'::"text" NOT NULL,
    "decided_by" "uuid",
    "decided_at" timestamp with time zone,
    "decision_note" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "time_off_requests_check" CHECK (("ends_on" >= "starts_on")),
    CONSTRAINT "time_off_requests_hours_requested_check" CHECK (("hours_requested" > (0)::numeric)),
    CONSTRAINT "time_off_requests_request_state_check" CHECK (("request_state" = ANY (ARRAY['pending'::"text", 'approved'::"text", 'denied'::"text", 'cancelled'::"text"])))
);


ALTER TABLE "public"."time_off_requests" OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."approve_time_off_request"("p_request_id" "uuid", "p_decider_id" "uuid", "p_decision_note" "text" DEFAULT NULL::"text") RETURNS "public"."time_off_requests"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_req public.time_off_requests%ROWTYPE;
  v_year int;
BEGIN
  -- Caller must be a member of the request's org. We re-check rather
  -- than rely on RLS because SECURITY DEFINER bypasses it.
  SELECT * INTO v_req FROM public.time_off_requests WHERE id = p_request_id AND request_state = 'pending';
  IF NOT FOUND THEN
    RAISE EXCEPTION 'time_off_request % not pending or not found', p_request_id;
  END IF;
  IF NOT private.is_org_member(v_req.org_id) THEN
    RAISE EXCEPTION 'caller not a member of org %', v_req.org_id;
  END IF;

  v_year := EXTRACT(YEAR FROM v_req.starts_on)::int;

  -- Decrement balance + bump used_ytd. Use UPSERT so first-approval-of-year
  -- creates the balance row if it didn't exist.
  INSERT INTO public.time_off_balances (org_id, user_id, policy_id, year, balance_hours, accrued_ytd_hours, used_ytd_hours)
  VALUES (v_req.org_id, v_req.user_id, v_req.policy_id, v_year, -v_req.hours_requested, 0, v_req.hours_requested)
  ON CONFLICT (user_id, policy_id, year)
  DO UPDATE SET
    balance_hours = public.time_off_balances.balance_hours - v_req.hours_requested,
    used_ytd_hours = public.time_off_balances.used_ytd_hours + v_req.hours_requested,
    updated_at = now();

  UPDATE public.time_off_requests
  SET request_state = 'approved',
      decided_by = p_decider_id,
      decided_at = now(),
      decision_note = p_decision_note
  WHERE id = p_request_id AND request_state = 'pending'
  RETURNING * INTO v_req;

  RETURN v_req;
END;
$$;


ALTER FUNCTION "public"."approve_time_off_request"("p_request_id" "uuid", "p_decider_id" "uuid", "p_decision_note" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."approve_time_off_request"("p_request_id" "uuid", "p_decider_id" "uuid", "p_decision_note" "text") IS 'Approve a pending time_off_request + decrement the matching balance. Called from console/workforce/time-off/actions.ts. SECURITY DEFINER but checks private.is_org_member before mutating.';



