CREATE OR REPLACE FUNCTION "public"."fx_rate_on"("p_from" "text", "p_to" "text", "p_date" "date") RETURNS numeric
    LANGUAGE "sql" STABLE
    AS $$
    select case
        when p_from = p_to then 1.0::numeric
        else (
            select rate from public.exchange_rates
            where from_currency = p_from and to_currency = p_to
              and effective_at <= (p_date + interval '1 day')
            order by effective_at desc, recorded_at desc limit 1
        )
    end
$$;


ALTER FUNCTION "public"."fx_rate_on"("p_from" "text", "p_to" "text", "p_date" "date") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fx_snapshot_for_expenses"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
declare v_entity_base text; v_rate_date date;
begin
    if new.entity_id is null then return new; end if;
    select base_currency into v_entity_base from public.org_entities where id = new.entity_id and deleted_at is null;
    if v_entity_base is null then return new; end if;
    v_rate_date := coalesce(new.spent_at, current_date);
    if new.fx_rate_to_base is null then new.fx_rate_to_base := public.fx_rate_on(new.currency, v_entity_base, v_rate_date); end if;
    if new.base_currency is null then new.base_currency := v_entity_base; end if;
    if new.base_amount_cents is null and new.fx_rate_to_base is not null then
        new.base_amount_cents := round(new.amount_cents::numeric * new.fx_rate_to_base);
    end if;
    return new;
end $$;


ALTER FUNCTION "public"."fx_snapshot_for_expenses"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."fx_snapshot_for_invoices"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
declare v_entity_base text; v_rate_date date;
begin
    if new.entity_id is null then return new; end if;
    select base_currency into v_entity_base from public.org_entities where id = new.entity_id and deleted_at is null;
    if v_entity_base is null then return new; end if;
    v_rate_date := coalesce(new.issued_at, current_date);
    if new.fx_rate_to_base is null then new.fx_rate_to_base := public.fx_rate_on(new.currency, v_entity_base, v_rate_date); end if;
    if new.base_currency is null then new.base_currency := v_entity_base; end if;
    if new.base_amount_cents is null and new.fx_rate_to_base is not null then
        new.base_amount_cents := round(new.amount_cents::numeric * new.fx_rate_to_base);
    end if;
    return new;
end $$;


