CREATE OR REPLACE FUNCTION "public"."mark_closed"("p_table" "text", "p_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
declare
  v_user uuid := auth.uid();
begin
  if p_id is null then
    raise exception 'mark_closed: id required';
  end if;

  case p_table
    when 'deliverables' then
      update public.deliverables
         set closed_at = coalesce(closed_at, now()),
             closed_by = coalesce(closed_by, v_user),
             updated_at = now()
       where id = p_id;
    when 'rfis' then
      update public.rfis
         set closed_at = coalesce(closed_at, now()),
             closed_by = coalesce(closed_by, v_user),
             updated_at = now()
       where id = p_id;
    when 'submittals' then
      update public.submittals
         set closed_at = coalesce(closed_at, now()),
             closed_by = coalesce(closed_by, v_user),
             updated_at = now()
       where id = p_id;
    when 'punch_items' then
      update public.punch_items
         set closed_at = coalesce(closed_at, now()),
             closed_by = coalesce(closed_by, v_user),
             updated_at = now()
       where id = p_id;
    when 'incidents' then
      update public.incidents
         set closed_at = coalesce(closed_at, now()),
             closed_by = coalesce(closed_by, v_user),
             updated_at = now()
       where id = p_id;
    else
      raise exception 'mark_closed: table % not whitelisted', p_table;
  end case;
end
$$;


ALTER FUNCTION "public"."mark_closed"("p_table" "text", "p_id" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."mark_closed"("p_table" "text", "p_id" "uuid") IS 'Lifecycle terminator. SECURITY DEFINER + EXECUTE TO authenticated is intentional — table whitelist prevents arbitrary writes; RLS gates row visibility before this fn even runs. Advisor warning accepted-by-design.';



CREATE OR REPLACE FUNCTION "public"."match_document_chunks"("query_embedding" "public"."vector", "match_top_k" integer DEFAULT 8, "min_similarity" numeric DEFAULT 0.65, "org_filter" "uuid" DEFAULT NULL::"uuid", "project_filter" "uuid" DEFAULT NULL::"uuid", "source_type_filter" "public"."embedding_source_type" DEFAULT NULL::"public"."embedding_source_type", "source_id_filter" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("id" "uuid", "source_type" "text", "source_id" "uuid", "chunk_text" "text", "chunk_ordinal" integer, "similarity" numeric)
    LANGUAGE "sql" STABLE
    AS $$
  SELECT
    dc.id,
    dc.source_type::text,
    dc.source_id,
    dc.chunk_text,
    dc.chunk_ordinal,
    (1 - (dc.embedding <=> query_embedding))::numeric AS similarity
  FROM public.document_chunks dc
  WHERE
    (org_filter IS NULL OR dc.org_id = org_filter)
    AND (project_filter IS NULL OR dc.project_id = project_filter)
    AND (source_type_filter IS NULL OR dc.source_type = source_type_filter)
    AND (source_id_filter IS NULL OR dc.source_id = source_id_filter)
    AND dc.embedding IS NOT NULL
    AND (1 - (dc.embedding <=> query_embedding)) >= min_similarity
  ORDER BY dc.embedding <=> query_embedding ASC
  LIMIT match_top_k
$$;


ALTER FUNCTION "public"."match_document_chunks"("query_embedding" "public"."vector", "match_top_k" integer, "min_similarity" numeric, "org_filter" "uuid", "project_filter" "uuid", "source_type_filter" "public"."embedding_source_type", "source_id_filter" "uuid") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."match_document_chunks"("query_embedding" "public"."vector", "match_top_k" integer, "min_similarity" numeric, "org_filter" "uuid", "project_filter" "uuid", "source_type_filter" "public"."embedding_source_type", "source_id_filter" "uuid") IS 'Cosine similarity search over document_chunks. Used by src/lib/ai/rag.ts. security_invoker so RLS still gates per-org reads.';



CREATE OR REPLACE FUNCTION "public"."next_sequence"("p_org_id" "uuid", "p_scope" "text", "p_format" "text" DEFAULT NULL::"text") RETURNS "text"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_format text;
  v_next   bigint;
  v_year   text := to_char(now() at time zone 'utc', 'YYYY');
  v_yy     text := to_char(now() at time zone 'utc', 'YY');
  v_mm     text := to_char(now() at time zone 'utc', 'MM');
  v_dd     text := to_char(now() at time zone 'utc', 'DD');
  v_slug   text;
  v_out    text;
  v_match  text;
  v_width  int;
begin
  if not is_org_member(p_org_id) then
    raise exception 'org_member_required' using errcode = '42501';
  end if;

  insert into org_sequences as s (org_id, scope, current_val, format)
  values (p_org_id, p_scope, 1, coalesce(p_format, 'SEQ-{seq:04}'))
  on conflict (org_id, scope) do update
    set current_val = s.current_val + 1,
        format      = coalesce(p_format, s.format),
        updated_at  = now()
  returning current_val, format into v_next, v_format;

  select upper(slug) into v_slug from orgs where id = p_org_id;
  if v_slug is null then v_slug := 'ORG'; end if;

  v_out := v_format;
  v_out := replace(v_out, '{YYYY}', v_year);
  v_out := replace(v_out, '{YY}',   v_yy);
  v_out := replace(v_out, '{MM}',   v_mm);
  v_out := replace(v_out, '{DD}',   v_dd);
  v_out := replace(v_out, '{ORG}',  v_slug);

  loop
    v_match := substring(v_out from '\{seq:(\d+)\}');
    if v_match is null then exit; end if;
    v_width := v_match::int;
    v_out := regexp_replace(v_out, '\{seq:\d+\}', lpad(v_next::text, v_width, '0'));
  end loop;

  v_out := replace(v_out, '{seq}', lpad(v_next::text, 4, '0'));

  return v_out;
end;
$$;


ALTER FUNCTION "public"."next_sequence"("p_org_id" "uuid", "p_scope" "text", "p_format" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."next_sequence"("p_org_id" "uuid", "p_scope" "text", "p_format" "text") IS 'Atomic per-org auto-number sequence. SECURITY DEFINER + service_role-only EXECUTE — callers run inside server actions that have already authed + org-scoped the user (see src/lib/sequences.ts).';



