CREATE OR REPLACE FUNCTION "public"."service_request_set_sla"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
declare
  policy record;
begin
  if new.sla_response_due is null or new.sla_resolution_due is null then
    select response_minutes, resolution_minutes into policy
      from service_sla_policies
     where org_id = new.org_id
       and severity = new.severity
       and active = true
     limit 1;
    if found then
      if new.sla_response_due is null then
        new.sla_response_due := new.opened_at + make_interval(mins => policy.response_minutes);
      end if;
      if new.sla_resolution_due is null then
        new.sla_resolution_due := new.opened_at + make_interval(mins => policy.resolution_minutes);
      end if;
    end if;
  end if;
  return new;
end;
$$;


ALTER FUNCTION "public"."service_request_set_sla"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."sign_msa"("p_token" "uuid", "p_code" "text", "p_signature" "text", "p_exhibit_b" "jsonb", "p_exhibit_c" "jsonb", "p_nscb_license" "text", "p_nscb_classification" "text", "p_nscb_monetary_limit_cents" bigint, "p_ip" "inet", "p_user_agent" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_catalog'
    AS $$
declare
  v_row          record;
  v_org_settings record;
begin
  select * into v_row
  from public.independent_contractor_msas
  where public_token = p_token
    and access_code  = upper(p_code)
    and (token_expires_at is null or token_expires_at > now())
    and msa_state not in ('signed','revoked','superseded')
  for update;
  if not found then raise exception 'MSA not found, expired, or already signed'; end if;

  select default_terms, default_governing_law into v_org_settings
  from public.org_offer_letter_settings where org_id = v_row.org_id;

  update public.independent_contractor_msas set
    msa_state                  = 'signed',
    signed_at                  = now(),
    signed_signature           = p_signature,
    signed_ip                  = p_ip,
    signed_user_agent          = p_user_agent,
    body_snapshot              = coalesce(body_snapshot, v_org_settings.default_terms),
    governing_law_snapshot     = coalesce(governing_law_snapshot, v_org_settings.default_governing_law),
    exhibit_b_other_clients    = coalesce(p_exhibit_b, '[]'::jsonb),
    exhibit_c_capital_items    = coalesce(p_exhibit_c, '[]'::jsonb),
    nscb_license_number        = p_nscb_license,
    nscb_classification        = p_nscb_classification,
    nscb_monetary_limit_cents  = p_nscb_monetary_limit_cents
  where id = v_row.id
  returning * into v_row;

  return to_jsonb(v_row);
end;
$$;


