CREATE TABLE IF NOT EXISTS "public"."site_plans" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "org_id" "uuid" NOT NULL,
    "project_id" "uuid",
    "venue_id" "uuid",
    "code" "text" NOT NULL,
    "title" "text" NOT NULL,
    "discipline" "text" DEFAULT 'site'::"text" NOT NULL,
    "current_revision_id" "uuid",
    "notes" "text",
    "created_by" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "atom_id" "text",
    "sheet_type" "public"."siteplan_sheet_type" DEFAULT 'site_plan'::"public"."siteplan_sheet_type" NOT NULL,
    "primary_class" smallint,
    "secondary_classes" smallint[] DEFAULT '{}'::smallint[],
    "tier_primary" smallint,
    "tier_secondary" "jsonb" DEFAULT '[]'::"jsonb",
    "shell_type" "public"."siteplan_shell_type",
    "shell_dimensions" "jsonb",
    "orientation_deg" smallint,
    "scale" "text",
    "document_state" "public"."siteplan_document_state" DEFAULT 'draft'::"public"."siteplan_document_state" NOT NULL,
    "superseded_by" "uuid",
    "issued_at" timestamp with time zone,
    "revision_letter" character(1) DEFAULT 'A'::"bpchar",
    "event_id" "uuid",
    "preset_code" "text",
    "zone_code" "text",
    "sustainability_tag" "text",
    "accessibility_tag" "text",
    "weather_exposure" "text",
    "security_level" "text",
    "sensitivity" "text",
    "approved_at" timestamp with time zone,
    "approved_by" "uuid",
    "submitted_at" timestamp with time zone,
    "submitted_by" "uuid",
    "deleted_at" timestamp with time zone,
    "storage_path" "text",
    CONSTRAINT "site_plans_accessibility_tag_check" CHECK (("accessibility_tag" = ANY (ARRAY['ada_compliant'::"text", 'partial'::"text", 'none'::"text"]))),
    CONSTRAINT "site_plans_atom_id_format" CHECK ((("atom_id" IS NULL) OR ("atom_id" ~ '^[A-Z0-9]{2,4}-[A-Z0-9]{3,5}[0-9]{2}-[A-Z0-9]{3,5}-[0-9]{4}\.[0-9]{3}\.[0-9]{3}-[A-Z0-9]{4,8}-[0-9]{3}[A-Z]$'::"text"))),
    CONSTRAINT "site_plans_discipline_check" CHECK (("discipline" = ANY (ARRAY['site'::"text", 'rigging'::"text", 'power'::"text", 'audio'::"text", 'video'::"text", 'lighting'::"text", 'comms'::"text", 'evacuation'::"text", 'hospitality'::"text", 'accessibility'::"text", 'sustainability'::"text", 'other'::"text"]))),
    CONSTRAINT "site_plans_orientation_deg_check" CHECK ((("orientation_deg" >= 0) AND ("orientation_deg" <= 359))),
    CONSTRAINT "site_plans_primary_class_check" CHECK ((("primary_class" >= 0) AND ("primary_class" <= 9))),
    CONSTRAINT "site_plans_revision_letter_check" CHECK (("revision_letter" ~ '^[A-Z]$'::"text")),
    CONSTRAINT "site_plans_security_level_check" CHECK (("security_level" = ANY (ARRAY['public'::"text", 'restricted'::"text", 'talent_only'::"text", 'exec'::"text"]))),
    CONSTRAINT "site_plans_sensitivity_check" CHECK (("sensitivity" = ANY (ARRAY['low'::"text", 'med'::"text", 'high'::"text"]))),
    CONSTRAINT "site_plans_sustainability_tag_check" CHECK (("sustainability_tag" = ANY (ARRAY['none'::"text", 'aspirational'::"text", 'committed'::"text", 'certified'::"text"]))),
    CONSTRAINT "site_plans_tier_primary_check" CHECK ((("tier_primary" >= 1) AND ("tier_primary" <= 6))),
    CONSTRAINT "site_plans_weather_exposure_check" CHECK (("weather_exposure" = ANY (ARRAY['enclosed'::"text", 'covered'::"text", 'open'::"text"])))
);


ALTER TABLE "public"."site_plans" OWNER TO "postgres";


COMMENT ON COLUMN "public"."site_plans"."atom_id" IS 'CHARTHOUSE atom identifier per protocol §3. Append-only once issued.';



COMMENT ON COLUMN "public"."site_plans"."sheet_type" IS 'CHARTHOUSE protocol §1.';



COMMENT ON COLUMN "public"."site_plans"."primary_class" IS 'Primary XPMS class 0..9.';



COMMENT ON COLUMN "public"."site_plans"."shell_dimensions" IS 'JSONB: {length_in, width_in, height_in, gross_sqft}.';



COMMENT ON COLUMN "public"."site_plans"."document_state" IS 'Lifecycle state per protocol §5.';



COMMENT ON COLUMN "public"."site_plans"."revision_letter" IS 'Single-letter revision per atom-id {REV}.';



COMMENT ON COLUMN "public"."site_plans"."storage_path" IS 'Storage object key for the rendered PDF in the site-plans bucket. NULL = no PDF uploaded yet (legacy spatial-only sheets).';



CREATE OR REPLACE FUNCTION "public"."siteplan_transition_state"("p_sheet_id" "uuid", "p_transition" "text") RETURNS "public"."site_plans"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
DECLARE
  v_sheet         public.site_plans;
  v_new_state     public.charthouse_document_state;
  v_user_id       uuid;
  v_region_count  int;
  v_band_count    int;
  v_adj_count     int;
BEGIN
  v_user_id := auth.uid();
  SELECT * INTO v_sheet FROM public.site_plans WHERE id = p_sheet_id;
  IF NOT FOUND THEN RAISE EXCEPTION 'charthouse: sheet not found' USING ERRCODE = 'P0002'; END IF;
  IF NOT private.is_org_member(v_sheet.org_id) THEN
    RAISE EXCEPTION 'charthouse: not authorized' USING ERRCODE = '42501';
  END IF;
  CASE p_transition
    WHEN 'submit' THEN
      IF v_sheet.document_state <> 'draft' THEN
        RAISE EXCEPTION 'charthouse: submit requires draft (was %)', v_sheet.document_state USING ERRCODE = '22023'; END IF;
      v_new_state := 'in_review';
    WHEN 'approve' THEN
      IF v_sheet.document_state <> 'in_review' THEN
        RAISE EXCEPTION 'charthouse: approve requires in_review (was %)', v_sheet.document_state USING ERRCODE = '22023'; END IF;
      v_new_state := 'approved';
    WHEN 'reject' THEN
      IF v_sheet.document_state <> 'in_review' THEN
        RAISE EXCEPTION 'charthouse: reject requires in_review (was %)', v_sheet.document_state USING ERRCODE = '22023'; END IF;
      v_new_state := 'draft';
    WHEN 'revise' THEN
      IF v_sheet.document_state NOT IN ('in_review','approved') THEN
        RAISE EXCEPTION 'charthouse: revise requires in_review or approved (was %)', v_sheet.document_state USING ERRCODE = '22023'; END IF;
      v_new_state := 'draft';
    WHEN 'issue' THEN
      IF v_sheet.document_state <> 'approved' THEN
        RAISE EXCEPTION 'charthouse: issue requires approved (was %)', v_sheet.document_state USING ERRCODE = '22023'; END IF;
      IF v_sheet.atom_id IS NULL THEN
        RAISE EXCEPTION 'charthouse: cannot issue without atom_id' USING ERRCODE = '22023'; END IF;
      IF v_sheet.shell_type IS NULL OR v_sheet.shell_dimensions IS NULL THEN
        RAISE EXCEPTION 'charthouse: cannot issue without shell_type + shell_dimensions' USING ERRCODE = '22023'; END IF;
      IF v_sheet.primary_class IS NULL THEN
        RAISE EXCEPTION 'charthouse: cannot issue without primary_class' USING ERRCODE = '22023'; END IF;
      SELECT count(*) INTO v_region_count FROM public.charthouse_zone_region WHERE sheet_id = p_sheet_id AND deleted_at IS NULL;
      IF v_region_count = 0 THEN
        RAISE EXCEPTION 'charthouse: cannot issue without at least one zone region' USING ERRCODE = '22023'; END IF;
      SELECT count(*) INTO v_band_count FROM public.charthouse_band WHERE sheet_id = p_sheet_id AND deleted_at IS NULL;
      IF v_band_count = 0 THEN
        RAISE EXCEPTION 'charthouse: cannot issue without at least one band' USING ERRCODE = '22023'; END IF;
      SELECT count(*) INTO v_adj_count FROM public.charthouse_adjacency WHERE sheet_id = p_sheet_id AND deleted_at IS NULL;
      IF v_adj_count < 4 THEN
        RAISE EXCEPTION 'charthouse: cannot issue without all four edges declared (have %, need 4)', v_adj_count USING ERRCODE = '22023'; END IF;
      v_new_state := 'issued';
    WHEN 'supersede' THEN
      IF v_sheet.document_state <> 'issued' THEN
        RAISE EXCEPTION 'charthouse: supersede requires issued (was %)', v_sheet.document_state USING ERRCODE = '22023'; END IF;
      v_new_state := 'superseded';
    WHEN 'field_change' THEN
      IF v_sheet.document_state <> 'issued' THEN
        RAISE EXCEPTION 'charthouse: field_change requires issued (was %)', v_sheet.document_state USING ERRCODE = '22023'; END IF;
      v_new_state := 'as_built';
    ELSE
      RAISE EXCEPTION 'charthouse: unknown transition %', p_transition USING ERRCODE = '22023';
  END CASE;
  UPDATE public.site_plans
     SET document_state = v_new_state,
         submitted_at = CASE WHEN p_transition = 'submit' THEN now() ELSE submitted_at END,
         submitted_by = CASE WHEN p_transition = 'submit' THEN v_user_id ELSE submitted_by END,
         approved_at  = CASE WHEN p_transition = 'approve' THEN now() ELSE approved_at END,
         approved_by  = CASE WHEN p_transition = 'approve' THEN v_user_id ELSE approved_by END,
         issued_at    = CASE WHEN p_transition = 'issue' THEN now() ELSE issued_at END,
         updated_at   = now()
   WHERE id = p_sheet_id
  RETURNING * INTO v_sheet;
  RETURN v_sheet;
END $$;


ALTER FUNCTION "public"."siteplan_transition_state"("p_sheet_id" "uuid", "p_transition" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."snapshot_deliverable_on_submit"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
begin
  if (old.fulfillment_state is distinct from new.fulfillment_state) and new.fulfillment_state = 'submitted' then
    new.version = old.version + 1;
    new.submitted_at = now();
    insert into deliverable_history (deliverable_id, version, data, changed_by)
    values (new.id, new.version, new.data, coalesce(new.submitted_by, old.submitted_by, auth.uid()));
  end if;
  return new;
end;
$$;


ALTER FUNCTION "public"."snapshot_deliverable_on_submit"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."snapshot_offer_letter"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
begin
  if (OLD.status = 'draft' and NEW.status <> 'draft') and NEW.snapshot is null then
    select to_jsonb(r.*) into NEW.snapshot
      from offer_letters_resolved r
      where r.id = NEW.id;
    NEW.snapshot_at := now();
  end if;
  return NEW;
end;
$$;


ALTER FUNCTION "public"."snapshot_offer_letter"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."sync_budget_for_bucket"("p_org_id" "uuid", "p_project_id" "uuid", "p_category" "text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_expense_total bigint;
  v_invoice_total bigint;
  v_total bigint;
begin
  select coalesce(sum(amount_cents), 0) into v_expense_total
  from expenses
  where org_id = p_org_id
    and (p_project_id is null or project_id = p_project_id)
    and (p_category   is null or category   = p_category);

  select coalesce(sum(amount_cents), 0) into v_invoice_total
  from invoices
  where org_id = p_org_id
    and status = 'paid'
    and (p_project_id is null or project_id = p_project_id);

  v_total := v_expense_total + v_invoice_total;

  update budgets
  set spent_cents = v_total
  where org_id = p_org_id
    and (project_id = p_project_id or (project_id is null and p_project_id is null))
    and (category   = p_category   or (category   is null and p_category   is null));
end;
$$;


ALTER FUNCTION "public"."sync_budget_for_bucket"("p_org_id" "uuid", "p_project_id" "uuid", "p_category" "text") OWNER TO "postgres";


COMMENT ON FUNCTION "public"."sync_budget_for_bucket"("p_org_id" "uuid", "p_project_id" "uuid", "p_category" "text") IS '3NF SSOT: recomputes budgets.spent_cents from live expenses + paid invoices. Authoritative — do not mutate budgets.spent_cents from application code.';



CREATE OR REPLACE FUNCTION "public"."tg_action_item_to_task"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  v_meeting RECORD;
  v_project_id uuid;
  v_org_id uuid;
  v_task_id uuid;
BEGIN
  IF NEW.assignee_user_id IS NULL THEN RETURN NEW; END IF;
  IF NEW.task_id IS NOT NULL THEN RETURN NEW; END IF;
  SELECT m.id, m.org_id, m.project_id INTO v_meeting FROM public.meetings m WHERE m.id = NEW.meeting_id;
  IF NOT FOUND THEN RETURN NEW; END IF;
  v_org_id := v_meeting.org_id;
  v_project_id := v_meeting.project_id;
  IF v_project_id IS NULL THEN RETURN NEW; END IF;
  INSERT INTO public.tasks (org_id, project_id, title, description, status, priority, due_at, assigned_to, created_by, created_at, updated_at)
  VALUES (v_org_id, v_project_id, LEFT(NEW.description, 200), 'Auto-created from meeting action item.', 'open', 'normal',
    CASE WHEN NEW.due_at IS NOT NULL THEN (NEW.due_at::timestamptz) ELSE NULL END,
    NEW.assignee_user_id, NEW.assignee_user_id, now(), now())
  RETURNING id INTO v_task_id;
  NEW.task_id := v_task_id;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."tg_action_item_to_task"() OWNER TO "postgres";


