CREATE OR REPLACE FUNCTION "public"."tg_fabrication_orders_phase_to_status"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  NEW.status := CASE NEW.production_phase
    WHEN 'DISCOVERY'   THEN 'open'
    WHEN 'CONCEPT'     THEN 'open'
    WHEN 'ENGINEERING' THEN 'in_progress'
    WHEN 'PRE_PRO'     THEN 'in_progress'
    WHEN 'FAB'         THEN 'in_progress'
    WHEN 'LOGISTICS'   THEN 'in_progress'
    WHEN 'INSTALL'     THEN 'in_progress'
    WHEN 'STRIKE'      THEN 'complete'
    WHEN 'ARCHIVED'    THEN 'complete'
    ELSE NEW.status
  END;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."tg_fabrication_orders_phase_to_status"() OWNER TO "postgres";


COMMENT ON FUNCTION "public"."tg_fabrication_orders_phase_to_status"() IS 'SOOT sync: production_phase is canonical; status is derived. Write production_phase.';



