CREATE OR REPLACE FUNCTION "public"."tg_inspection_item_to_punch"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
DECLARE
  v_inspection RECORD;
  v_project_id uuid;
  v_org_id uuid;
  v_punch_code text;
BEGIN
  IF NEW.result IS NULL OR NEW.result <> 'fail' THEN RETURN NEW; END IF;
  IF (TG_OP = 'UPDATE' AND OLD.result = 'fail') THEN RETURN NEW; END IF;
  SELECT i.id, i.org_id, i.project_id INTO v_inspection FROM public.inspections i WHERE i.id = NEW.inspection_id;
  IF NOT FOUND THEN RETURN NEW; END IF;
  v_org_id := v_inspection.org_id;
  v_project_id := v_inspection.project_id;
  IF v_project_id IS NULL THEN RETURN NEW; END IF;
  v_punch_code := 'PUNCH-INSP-' || substr(NEW.id::text, 1, 8);
  INSERT INTO public.punch_items (org_id, project_id, code, title, description, priority, status, photo_path, created_at)
  VALUES (v_org_id, v_project_id, v_punch_code, COALESCE(NEW.prompt, 'Inspection failure'), NEW.notes, 'normal', 'open', NEW.photo_path, now())
  ON CONFLICT (org_id, code) DO NOTHING;
  RETURN NEW;
END;
$$;


ALTER FUNCTION "public"."tg_inspection_item_to_punch"() OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."tg_je_balance"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public', 'pg_catalog'
    AS $$
DECLARE d bigint; c bigint;
BEGIN
  SELECT COALESCE(SUM(base_debit_minor),0), COALESCE(SUM(base_credit_minor),0)
    INTO d, c
    FROM public.journal_entry_lines
    WHERE journal_entry_id = NEW.journal_entry_id;
  IF d <> c THEN
    RAISE EXCEPTION 'ULG journal entry % unbalanced: debits=% credits=%',
      NEW.journal_entry_id, d, c;
  END IF;
  RETURN NEW;
END $$;


ALTER FUNCTION "public"."tg_je_balance"() OWNER TO "postgres";


