CREATE OR REPLACE FUNCTION "public"."uap_emit"("p_org_id" "uuid", "p_subsystem" "text", "p_event_type" "text", "p_target_table" "text", "p_target_id" "uuid", "p_actor_id" "uuid", "p_actor_party_id" "uuid", "p_payload" "jsonb", "p_correlation_id" "uuid", "p_idempotency_key" "text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_catalog'
    AS $$
DECLARE
  v_id uuid;
BEGIN
  IF p_idempotency_key IS NOT NULL THEN
    SELECT id INTO v_id FROM public.audit_events WHERE org_id = p_org_id AND idempotency_key = p_idempotency_key;
    IF v_id IS NOT NULL THEN RETURN v_id; END IF;
  END IF;
  INSERT INTO public.audit_events (
    org_id, actor_id, actor_party_id, action, target_table, target_id,
    metadata, subsystem_origin, event_type, correlation_id, idempotency_key, operation
  ) VALUES (
    p_org_id, p_actor_id, p_actor_party_id, p_event_type,
    p_target_table, p_target_id,
    p_payload, p_subsystem, p_event_type, p_correlation_id, p_idempotency_key, 'EMIT'
  ) RETURNING id INTO v_id;
  RETURN v_id;
END $$;


ALTER FUNCTION "public"."uap_emit"("p_org_id" "uuid", "p_subsystem" "text", "p_event_type" "text", "p_target_table" "text", "p_target_id" "uuid", "p_actor_id" "uuid", "p_actor_party_id" "uuid", "p_payload" "jsonb", "p_correlation_id" "uuid", "p_idempotency_key" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."umc_currency_check"("curr" "text") RETURNS boolean
    LANGUAGE "sql" IMMUTABLE PARALLEL SAFE
    SET "search_path" TO 'public', 'pg_catalog'
    AS $_$ SELECT curr ~ '^[A-Z]{3}$' AND EXISTS (SELECT 1 FROM public.currencies WHERE code = curr) $_$;


ALTER FUNCTION "public"."umc_currency_check"("curr" "text") OWNER TO "postgres";


CREATE OR REPLACE FUNCTION "public"."xpms_build_identifier"("p_org_token" "text", "p_event_token" "text", "p_event_year" smallint, "p_venue_token" "text", "p_class" smallint, "p_division" smallint, "p_section" smallint, "p_zone_token" "text", "p_sequence_no" integer, "p_revision" "text") RETURNS "text"
    LANGUAGE "sql" IMMUTABLE
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
  select format(
    '%s-%s%s%s-%s.%s.%s-%s-%s%s',
    upper(p_org_token),
    upper(p_event_token),
    lpad(p_event_year::text, 2, '0'),
    upper(p_venue_token),
    p_class::text,
    p_division::text,
    p_section::text,
    upper(p_zone_token),
    lpad(p_sequence_no::text, 4, '0'),
    upper(p_revision)
  );
$$;


