CREATE TABLE IF NOT EXISTS "public"."assignments" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "org_id" "uuid" NOT NULL,
    "project_id" "uuid" NOT NULL,
    "catalog_item_id" "uuid" NOT NULL,
    "catalog_kind" "public"."catalog_kind" NOT NULL,
    "party_kind" "public"."assignment_party_kind" NOT NULL,
    "party_user_id" "uuid",
    "party_crew_id" "uuid",
    "party_external_id" "uuid",
    "fulfillment_state" "public"."fulfillment_state" DEFAULT 'briefed'::"public"."fulfillment_state" NOT NULL,
    "title" "text",
    "notes" "text",
    "data" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "atom_id" "uuid",
    "issued_at" timestamp with time zone,
    "deadline" timestamp with time zone,
    "fulfilled_at" timestamp with time zone,
    "version" integer DEFAULT 1 NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "created_by" "uuid",
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "deleted_at" timestamp with time zone,
    "closed_at" timestamp with time zone,
    "closed_by" "uuid",
    CONSTRAINT "assignments_check" CHECK (((("party_kind" = 'user'::"public"."assignment_party_kind") AND ("party_user_id" IS NOT NULL) AND ("party_crew_id" IS NULL) AND ("party_external_id" IS NULL)) OR (("party_kind" = 'crew_member'::"public"."assignment_party_kind") AND ("party_crew_id" IS NOT NULL) AND ("party_user_id" IS NULL) AND ("party_external_id" IS NULL)) OR (("party_kind" = 'external_holder'::"public"."assignment_party_kind") AND ("party_external_id" IS NOT NULL) AND ("party_user_id" IS NULL) AND ("party_crew_id" IS NULL))))
);


ALTER TABLE "public"."assignments" OWNER TO "postgres";


COMMENT ON TABLE "public"."assignments" IS 'Canonical per-individual entitlement table. Every ticket, credential, meal, radio, uniform, hotel room, tool, equipment kit, vehicle, travel itinerary, and visa packet is an assignment row. Project-document deliverables (riders, plots, lists) stay in public.deliverables.';



