CREATE TABLE IF NOT EXISTS "public"."budgets" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "org_id" "uuid" NOT NULL,
    "project_id" "uuid",
    "name" "text" NOT NULL,
    "category" "text",
    "amount_cents" bigint DEFAULT 0 NOT NULL,
    "spent_cents" bigint DEFAULT 0 NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "code" "text",
    "committed_cents" bigint DEFAULT 0 NOT NULL,
    "forecast_cents" bigint DEFAULT 0 NOT NULL,
    "eac_cents" bigint DEFAULT 0 NOT NULL,
    "notes" "text",
    "xtc_code" integer,
    "currency" "text" DEFAULT 'USD'::"text" NOT NULL,
    "event" "text",
    "location" "text",
    "activation" "text",
    "department" "text",
    "team" "text",
    "class" "text",
    "item" "text",
    "discipline" "public"."budget_discipline",
    "xpms_phase" "text",
    "tier" "public"."budget_tier",
    "xyz" "public"."budget_xyz",
    "line_type" "public"."budget_line_type" DEFAULT 'Scope'::"public"."budget_line_type" NOT NULL,
    "quantity" numeric(18,4),
    "rate_cents" bigint,
    "estimate_cents" bigint,
    "actual_cents" bigint,
    "vendor" "text",
    "budget_status" "text",
    "flag" boolean DEFAULT false NOT NULL,
    "external_notes" "text",
    "internal_notes" "text",
    "scope" "text" DEFAULT 'canonical'::"text" NOT NULL,
    CONSTRAINT "budgets_scope_check" CHECK (("scope" = ANY (ARRAY['canonical'::"text", 'external_example'::"text"]))),
    CONSTRAINT "budgets_xpms_phase_check" CHECK ((("xpms_phase" IS NULL) OR ("xpms_phase" = ANY (ARRAY['Discovery'::"text", 'Design'::"text", 'Advance'::"text", 'Procurement'::"text", 'Build'::"text", 'Install'::"text", 'Operate'::"text", 'Close'::"text"]))))
);


ALTER TABLE "public"."budgets" OWNER TO "postgres";


COMMENT ON COLUMN "public"."budgets"."category" IS 'DEPRECATED (P4) — replaced by budgets.department (XPMS enum). Migration 0070+ uses department; this column survives for legacy read compatibility only.';



COMMENT ON COLUMN "public"."budgets"."amount_cents" IS 'BUDGET column from XPMS template — the approved baseline.';



COMMENT ON COLUMN "public"."budgets"."spent_cents" IS 'DEPRECATED (P4) — replaced by budgets.actual_cents (auto-computed by expenses trigger). Kept in sync by migration 0073 trigger function.';



COMMENT ON COLUMN "public"."budgets"."code" IS 'DEPRECATED (P4) — replaced by the budgets.id UUID. Custom codes survive on existing rows; new rows should leave NULL.';



COMMENT ON COLUMN "public"."budgets"."forecast_cents" IS 'FORECAST column from XPMS template. VARIANCE = BUDGET - FORECAST is computed at read time (no column).';



COMMENT ON COLUMN "public"."budgets"."notes" IS 'DEPRECATED (P4) — split into budgets.external_notes (client-visible) and budgets.internal_notes (org-only) by migration 0070.';



COMMENT ON COLUMN "public"."budgets"."xtc_code" IS 'DEPRECATED (P4) — pre-XPMS classification code. No replacement; rows with xtc_code should be re-tagged with department/discipline/xpms_phase.';



COMMENT ON COLUMN "public"."budgets"."discipline" IS 'Multidisciplinary work axis (Live Entertainment / Experiential / Fabrication / Construction / Interior Design / Procurement / Broadcast & Content / Corporate & Brand / Hospitality & F&B / Festival & Touring).';



COMMENT ON COLUMN "public"."budgets"."xpms_phase" IS 'XPMS 8-Gate Lifecycle phase: Discovery / Design / Advance / Procurement / Build / Install / Operate / Close. NULL for non-scope rows (Fee, Contingency) that don''t belong to a phase.';



COMMENT ON COLUMN "public"."budgets"."tier" IS 'Experience tier (01 Social / 02 Digital / 03 Virtual / 04 Physical / 05 Experiential / 06 Theatrical).';



COMMENT ON COLUMN "public"."budgets"."xyz" IS 'Cost behaviour axis: X (Constant fixed cost), Y (Variable per unit), Z (Timeline/Phase-dependent).';



COMMENT ON COLUMN "public"."budgets"."line_type" IS 'XPMS budget line classification (Scope/Fee/Contingency/Allowance/Markup). The phase curve sums LINE TYPE = Scope only — Fee & Contingency roll up separately and never inflate a phase total.';



COMMENT ON COLUMN "public"."budgets"."estimate_cents" IS 'Computed: QUANTITY × RATE_CENTS via trigger. Null when quantity or rate are unset.';



COMMENT ON COLUMN "public"."budgets"."actual_cents" IS 'ACTUAL column from XPMS template — rolled up from the Expenses ledger.';



