);


ALTER TABLE "public"."expenses" OWNER TO "postgres";


COMMENT ON COLUMN "public"."expenses"."category" IS 'DEPRECATED (P4) — replaced by expenses.department (XPMS enum) plus discipline/xpms_phase. Migration 0071 backfilled department from category where it matched a canonical XPMS class.';



COMMENT ON COLUMN "public"."expenses"."status" IS 'DEPRECATED (P4) — replaced by receipt_state per LDP §NAMING DISCIPLINE (`status` banned in new tables). Kept in sync by trigger; new code should read receipt_state.';



COMMENT ON COLUMN "public"."expenses"."xtc_code" IS 'DEPRECATED (P4) — pre-XPMS classification code. No replacement.';



COMMENT ON COLUMN "public"."expenses"."department" IS 'XPMS class label — joins to budgets.department for the actuals rollup. Backfilled from category in 0071.';



COMMENT ON COLUMN "public"."expenses"."xpms_phase" IS 'XPMS 8-Gate Lifecycle phase for the expense.';



COMMENT ON COLUMN "public"."expenses"."receipt_state" IS 'LDP §NAMING DISCIPLINE — canonical post-rename column. Kept in sync with the legacy `status` column by tg_expenses_sync_receipt_state until phase 3 drops `status`.';



