    CONSTRAINT "je_line_xor" CHECK (((("debit_minor" > 0) AND ("credit_minor" = 0)) OR (("credit_minor" > 0) AND ("debit_minor" = 0))))
);


ALTER TABLE "public"."journal_entry_lines" OWNER TO "postgres";


CREATE MATERIALIZED VIEW "public"."general_ledger_balances" AS
 SELECT "je"."org_id",
    "jel"."account_id",
    "jel"."cost_center_id",
    "jel"."base_currency" AS "currency",
    "date_trunc"('month'::"text", "je"."posted_at") AS "month",
    ("sum"("jel"."base_debit_minor") - "sum"("jel"."base_credit_minor")) AS "net_minor"
   FROM ("public"."journal_entry_lines" "jel"
     JOIN "public"."journal_entries" "je" ON (("je"."id" = "jel"."journal_entry_id")))
  GROUP BY "je"."org_id", "jel"."account_id", "jel"."cost_center_id", "jel"."base_currency", ("date_trunc"('month'::"text", "je"."posted_at"))
  WITH NO DATA;


ALTER MATERIALIZED VIEW "public"."general_ledger_balances" OWNER TO "postgres";


