   FROM ( VALUES ('announcement'::"text",'Updates'::"text",'Org-wide announcements'::"text"), ('chat'::"text",'Chat'::"text",'Direct messages and channels'::"text"), ('kudos'::"text",'Kudos'::"text",'Recognition posts'::"text"), ('badge'::"text",'Badges'::"text",'Awards from your org'::"text"), ('assignment'::"text",'Assignments'::"text",'New tickets, credentials, and advancing items assigned to you'::"text"), ('assignment_state'::"text",'Assignment state'::"text",'State changes on assignments you own'::"text"), ('assignment_scan'::"text",'Scans'::"text",'Your ticket or credential was scanned'::"text"), ('shift_swap'::"text",'Shift Swap'::"text",'Swap request decisions'::"text"), ('time_off'::"text",'Time Off'::"text",'Time-off request decisions'::"text"), ('course'::"text",'Courses'::"text",'Course assignments + pass results'::"text"), ('incident'::"text",'Incidents'::"text",'Field incident updates (manager+ only)'::"text")) "t"("kind", "label", "description");


