CREATE OR REPLACE VIEW "public"."public_insights_pool" WITH ("security_invoker"='on') AS
 SELECT ("date_trunc"('month'::"text", ("s"."show_date")::timestamp with time zone))::"date" AS "month",
    "unnest"(COALESCE("tp"."genre_tags", ARRAY['unknown'::"text"])) AS "genre",
    "count"(*) AS "show_count",
    ("avg"("s"."gross_box_office_cents"))::bigint AS "avg_gross_cents",
    ("avg"("s"."paid_attendance"))::integer AS "avg_attendance",
    ("avg"("s"."artist_payout_cents"))::bigint AS "avg_artist_payout_cents"
   FROM ((("public"."settlements" "s"
     JOIN "public"."orgs" "o" ON ((("o"."id" = "s"."org_id") AND ("o"."insights_opt_in" = true))))
     LEFT JOIN "public"."talent_offers" "o2" ON (("o2"."id" = "s"."talent_offer_id")))
     LEFT JOIN "public"."talent_profiles" "tp" ON (("tp"."id" = "o2"."talent_profile_id")))
  WHERE ("s"."status" = 'final'::"public"."settlement_status")
  GROUP BY (("date_trunc"('month'::"text", ("s"."show_date")::timestamp with time zone))::"date"), ("unnest"(COALESCE("tp"."genre_tags", ARRAY['unknown'::"text"])))
 HAVING ("count"(*) >= 3);


ALTER VIEW "public"."public_insights_pool" OWNER TO "postgres";


