CREATE OR REPLACE VIEW "public"."tour_p_and_l" WITH ("security_invoker"='on') AS
 SELECT "t"."id" AS "tour_id",
    "t"."org_id",
    "t"."name",
    "t"."status",
    "t"."starts_on",
    "t"."ends_on",
    "count"(DISTINCT "o"."id") AS "leg_count",
    "count"(DISTINCT "s"."id") AS "settled_legs",
    COALESCE("sum"("s"."gross_box_office_cents"), (0)::numeric) AS "gross_box_office_cents",
    COALESCE("sum"("s"."nbor_cents"), (0)::numeric) AS "nbor_cents",
    COALESCE("sum"("s"."artist_payout_cents"), (0)::numeric) AS "artist_payout_cents",
    COALESCE("sum"("s"."agent_commission_cents"), (0)::numeric) AS "agent_commission_cents",
    COALESCE("sum"((("s"."bar_revenue_cents" + "s"."merch_revenue_cents") + "s"."other_revenue_cents")), (0)::numeric) AS "ancillary_revenue_cents"
   FROM (("public"."tours" "t"
     LEFT JOIN "public"."talent_offers" "o" ON (("o"."tour_id" = "t"."id")))
     LEFT JOIN "public"."settlements" "s" ON (("s"."talent_offer_id" = "o"."id")))
  WHERE ("t"."deleted_at" IS NULL)
  GROUP BY "t"."id", "t"."org_id", "t"."name", "t"."status", "t"."starts_on", "t"."ends_on";


ALTER VIEW "public"."tour_p_and_l" OWNER TO "postgres";


