    "recipient_kind" "public"."transmittal_recipient_kind" NOT NULL,
    "user_id" "uuid",
    "vendor_id" "uuid",
    "external_email" "text",
    "cc" boolean DEFAULT false NOT NULL,
    "delivered_at" timestamp with time zone,
    "failed_at" timestamp with time zone,
    "failed_reason" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "transmittal_recipient_exactly_one" CHECK ((((
CASE
    WHEN ("user_id" IS NOT NULL) THEN 1
    ELSE 0
END +
CASE
    WHEN ("vendor_id" IS NOT NULL) THEN 1
    ELSE 0
END) +
CASE
    WHEN ("external_email" IS NOT NULL) THEN 1
    ELSE 0
END) = 1)),
    CONSTRAINT "transmittal_recipient_kind_matches" CHECK (((("recipient_kind" = 'user'::"public"."transmittal_recipient_kind") AND ("user_id" IS NOT NULL)) OR (("recipient_kind" = 'vendor'::"public"."transmittal_recipient_kind") AND ("vendor_id" IS NOT NULL)) OR (("recipient_kind" = 'external_email'::"public"."transmittal_recipient_kind") AND ("external_email" IS NOT NULL))))
);


