CREATE OR REPLACE VIEW "public"."v_action_items" WITH ("security_invoker"='true') AS
 SELECT 'rfi'::"text" AS "kind",
    "r"."id" AS "record_id",
    "r"."org_id",
    "r"."project_id",
    "r"."subject" AS "title",
    "r"."ball_in_court_id" AS "owner_id",
    "r"."due_at",
    "r"."status",
    "r"."priority",
    "r"."created_at"
   FROM "public"."rfis" "r"
  WHERE ("r"."status" = 'open'::"text")
UNION ALL
 SELECT 'submittal'::"text" AS "kind",
    "s"."id" AS "record_id",
    "s"."org_id",
    "s"."project_id",
    "s"."title",
    "s"."ball_in_court_id" AS "owner_id",
    "s"."due_at",
    "s"."status",
    'normal'::"text" AS "priority",
    "s"."created_at"
   FROM "public"."submittals" "s"
  WHERE ("s"."status" = ANY (ARRAY['submitted'::"text", 'in_review'::"text", 'revise_resubmit'::"text"]))
UNION ALL
 SELECT 'punch'::"text" AS "kind",
    "p"."id" AS "record_id",
    "p"."org_id",
    "p"."project_id",
    "p"."title",
    "p"."assignee_id" AS "owner_id",
    "p"."due_at",
    "p"."status",
    "p"."priority",
    "p"."created_at"
   FROM "public"."punch_items" "p"
  WHERE ("p"."status" = ANY (ARRAY['open'::"text", 'in_progress'::"text", 'ready_for_review'::"text"]))
UNION ALL
 SELECT 'inspection'::"text" AS "kind",
    "i"."id" AS "record_id",
    "i"."org_id",
    "i"."project_id",
    "i"."name" AS "title",
    "i"."inspector_id" AS "owner_id",
    ("i"."scheduled_for")::"date" AS "due_at",
    "i"."status",
    'normal'::"text" AS "priority",
    "i"."created_at"
   FROM "public"."inspections" "i"
  WHERE ("i"."status" = ANY (ARRAY['scheduled'::"text", 'in_progress'::"text"]))
UNION ALL
 SELECT 'task'::"text" AS "kind",
    "t"."id" AS "record_id",
    "t"."org_id",
    "t"."project_id",
    "t"."title",
    "t"."assigned_to" AS "owner_id",
    "t"."due_at",
    ("t"."status")::"text" AS "status",
    'normal'::"text" AS "priority",
    "t"."created_at"
   FROM "public"."tasks" "t"
  WHERE ("t"."status" = ANY (ARRAY['todo'::"public"."task_status", 'in_progress'::"public"."task_status", 'blocked'::"public"."task_status", 'review'::"public"."task_status"]));


ALTER VIEW "public"."v_action_items" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_budget_health" WITH ("security_invoker"='true') AS
 SELECT "id",
    "org_id",
    "project_id",
    "name",
    "code",
    "amount_cents" AS "budget_cents",
    "committed_cents",
    "spent_cents",
    "forecast_cents",
    GREATEST("forecast_cents", ("committed_cents" + "spent_cents")) AS "eac_cents",
    ("amount_cents" - GREATEST("forecast_cents", ("committed_cents" + "spent_cents"))) AS "variance_cents",
        CASE
            WHEN ("amount_cents" = 0) THEN (0)::numeric
            ELSE "round"(((100.0 * ("spent_cents")::numeric) / ("amount_cents")::numeric), 2)
        END AS "pct_spent"
   FROM "public"."budgets" "b";


ALTER VIEW "public"."v_budget_health" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_catalog_inventory" WITH ("security_invoker"='true') AS
 SELECT "c"."id" AS "catalog_item_id",
    "c"."org_id",
    "c"."kind" AS "catalog_kind",
    "c"."code",
    "c"."name",
    "c"."inventory_qty" AS "allocated",
    ("count"("a".*) FILTER (WHERE ("a"."fulfillment_state" = ANY (ARRAY['issued'::"public"."fulfillment_state", 'transferred'::"public"."fulfillment_state", 'briefed'::"public"."fulfillment_state", 'draft'::"public"."fulfillment_state", 'submitted'::"public"."fulfillment_state", 'in_review'::"public"."fulfillment_state", 'revision_requested'::"public"."fulfillment_state", 'approved'::"public"."fulfillment_state"]))))::integer AS "open_count",
    ("count"("a".*) FILTER (WHERE ("a"."fulfillment_state" = ANY (ARRAY['redeemed'::"public"."fulfillment_state", 'delivered'::"public"."fulfillment_state", 'returned'::"public"."fulfillment_state"]))))::integer AS "fulfilled_count",
    ("count"("a".*) FILTER (WHERE ("a"."fulfillment_state" = ANY (ARRAY['voided'::"public"."fulfillment_state", 'rejected'::"public"."fulfillment_state", 'expired'::"public"."fulfillment_state"]))))::integer AS "cancelled_count",
    ("count"("a".*) FILTER (WHERE ("a"."deleted_at" IS NULL)))::integer AS "total_count",
        CASE
            WHEN ("c"."inventory_qty" IS NULL) THEN NULL::integer
            ELSE ("c"."inventory_qty" - ("count"("a".*) FILTER (WHERE ("a"."fulfillment_state" = ANY (ARRAY['issued'::"public"."fulfillment_state", 'transferred'::"public"."fulfillment_state", 'redeemed'::"public"."fulfillment_state", 'delivered'::"public"."fulfillment_state"]))))::integer)
        END AS "available_count"
   FROM ("public"."master_catalog_items" "c"
     LEFT JOIN "public"."assignments" "a" ON ((("a"."catalog_item_id" = "c"."id") AND ("a"."deleted_at" IS NULL))))
  WHERE ("c"."deleted_at" IS NULL)
  GROUP BY "c"."id", "c"."org_id", "c"."kind", "c"."code", "c"."name", "c"."inventory_qty";


ALTER VIEW "public"."v_catalog_inventory" OWNER TO "postgres";


COMMENT ON VIEW "public"."v_catalog_inventory" IS 'Live inventory rollup per master_catalog_items row. Replaces the denormalized ticket_types.sold counter.';



CREATE OR REPLACE VIEW "public"."v_consolidated_ar" AS
 SELECT "i"."org_id",
    "i"."entity_id",
    "e"."legal_name" AS "entity_legal_name",
    "e"."short_code" AS "entity_short_code",
    "e"."parent_entity_id",
    "e"."consolidation_method",
    "e"."ownership_pct",
    "i"."id",
    "i"."number",
    "i"."title",
    "i"."currency",
    "i"."amount_cents",
    "i"."base_currency",
    "i"."base_amount_cents",
    "i"."fx_rate_to_base",
    "i"."issued_at",
    "i"."due_at",
    "i"."paid_at",
    "i"."status" AS "invoice_status",
    "i"."project_id",
    "i"."client_id",
        CASE
            WHEN ("e"."consolidation_method" = 'proportional'::"text") THEN "round"((((COALESCE("i"."base_amount_cents", "i"."amount_cents"))::numeric * "e"."ownership_pct") / 100.0))
            WHEN ("e"."consolidation_method" = 'none'::"text") THEN (0)::numeric
            ELSE (COALESCE("i"."base_amount_cents", "i"."amount_cents"))::numeric
        END AS "consolidated_amount_cents"
   FROM ("public"."invoices" "i"
     LEFT JOIN "public"."org_entities" "e" ON ((("e"."id" = "i"."entity_id") AND ("e"."deleted_at" IS NULL))))
  WHERE ("i"."deleted_at" IS NULL);


ALTER VIEW "public"."v_consolidated_ar" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_equipment_utilization" WITH ("security_invoker"='true') AS
 WITH "movements" AS (
         SELECT "e"."id" AS "equipment_id",
            "e"."org_id",
            "e"."category",
            "e"."name",
            "e"."asset_tag",
            "e"."status",
            "e"."daily_rate_cents",
            "e"."daily_rate_currency",
            ("count"("am".*) FILTER (WHERE (("am"."movement_kind" = ANY (ARRAY['checkout'::"text", 'reserve'::"text", 'transfer'::"text"])) AND ("am"."occurred_at" >= ("now"() - '30 days'::interval)))))::integer AS "movements_30d",
            ("count"("am".*) FILTER (WHERE (("am"."movement_kind" = ANY (ARRAY['checkout'::"text", 'reserve'::"text", 'transfer'::"text"])) AND ("am"."occurred_at" >= ("now"() - '90 days'::interval)))))::integer AS "movements_90d",
            (COALESCE("sum"(
                CASE
                    WHEN (("am"."movement_kind" = 'reserve'::"text") AND ("am"."reservation_starts_at" IS NOT NULL) AND ("am"."reservation_ends_at" IS NOT NULL) AND ("am"."occurred_at" >= ("now"() - '30 days'::interval))) THEN GREATEST((0)::numeric, (EXTRACT(epoch FROM ("am"."reservation_ends_at" - "am"."reservation_starts_at")) / (86400)::numeric))
                    ELSE (0)::numeric
                END), (0)::numeric))::numeric(10,2) AS "reserved_days_30d",
            (COALESCE("sum"(
                CASE
                    WHEN (("am"."movement_kind" = 'reserve'::"text") AND ("am"."reservation_starts_at" IS NOT NULL) AND ("am"."reservation_ends_at" IS NOT NULL) AND ("am"."occurred_at" >= ("now"() - '90 days'::interval))) THEN GREATEST((0)::numeric, (EXTRACT(epoch FROM ("am"."reservation_ends_at" - "am"."reservation_starts_at")) / (86400)::numeric))
                    ELSE (0)::numeric
                END), (0)::numeric))::numeric(10,2) AS "reserved_days_90d",
            "max"("am"."occurred_at") FILTER (WHERE ("am"."movement_kind" = ANY (ARRAY['checkout'::"text", 'reserve'::"text", 'transfer'::"text"]))) AS "last_active_at"
           FROM ("public"."equipment" "e"
             LEFT JOIN "public"."asset_movements" "am" ON (("am"."asset_id" = "e"."id")))
          WHERE ("e"."deleted_at" IS NULL)
          GROUP BY "e"."id", "e"."org_id", "e"."category", "e"."name", "e"."asset_tag", "e"."status", "e"."daily_rate_cents", "e"."daily_rate_currency"
        )
 SELECT "equipment_id",
    "org_id",
    "category",
    "name",
    "asset_tag",
    "status",
    "daily_rate_cents",
    "daily_rate_currency",
    "movements_30d",
    "movements_90d",
    "reserved_days_30d",
    "reserved_days_90d",
    "last_active_at",
    "round"((("reserved_days_30d" / 30.0) * (100)::numeric), 1) AS "utilization_pct_30d",
    "round"((("reserved_days_90d" / 90.0) * (100)::numeric), 1) AS "utilization_pct_90d",
        CASE
            WHEN ("daily_rate_cents" IS NOT NULL) THEN ((((30)::numeric - LEAST("reserved_days_30d", (30)::numeric)) * ("daily_rate_cents")::numeric))::bigint
            ELSE NULL::bigint
        END AS "idle_revenue_30d_cents"
   FROM "movements" "m";


ALTER VIEW "public"."v_equipment_utilization" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_siteplan_sheet_acceptance" AS
 SELECT "id" AS "sheet_id",
    "org_id",
    "atom_id",
    "document_state",
    ("atom_id" IS NOT NULL) AS "has_atom_id",
    ("sheet_type" IS NOT NULL) AS "has_sheet_type",
    ("primary_class" IS NOT NULL) AS "has_primary_class",
    ("tier_primary" IS NOT NULL) AS "has_tier_primary",
    (("shell_type" IS NOT NULL) AND ("shell_dimensions" IS NOT NULL)) AS "has_shell",
    (( SELECT "count"(*) AS "count"
           FROM "public"."siteplan_zone_region" "z"
          WHERE (("z"."sheet_id" = "sp"."id") AND ("z"."deleted_at" IS NULL))) > 0) AS "has_region",
    (( SELECT "count"(*) AS "count"
           FROM "public"."siteplan_band" "b"
          WHERE (("b"."sheet_id" = "sp"."id") AND ("b"."deleted_at" IS NULL))) > 0) AS "has_band",
    (( SELECT "count"(*) AS "count"
           FROM "public"."siteplan_placement" "p"
          WHERE (("p"."sheet_id" = "sp"."id") AND ("p"."deleted_at" IS NULL))) > 0) AS "has_placement",
    (( SELECT "count"(*) AS "count"
           FROM "public"."siteplan_utility" "u"
          WHERE (("u"."sheet_id" = "sp"."id") AND ("u"."deleted_at" IS NULL))) > 0) AS "has_utility",
    (( SELECT "count"(*) AS "count"
           FROM "public"."siteplan_adjacency" "a"
          WHERE (("a"."sheet_id" = "sp"."id") AND ("a"."deleted_at" IS NULL))) >= 4) AS "has_all_four_edges",
    ("approved_at" IS NOT NULL) AS "has_approval_signoff"
   FROM "public"."site_plans" "sp"
  WHERE ("deleted_at" IS NULL);


ALTER VIEW "public"."v_siteplan_sheet_acceptance" OWNER TO "postgres";


CREATE TABLE IF NOT EXISTS "public"."xpms_atoms" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "org_id" "uuid" NOT NULL,
    "project_id" "uuid",
    "identifier" "text" NOT NULL,
    "xtc_code" integer NOT NULL,
    "class_code" smallint NOT NULL,
    "division_code" smallint NOT NULL,
    "section_code" smallint NOT NULL,
    "org_token" "text" NOT NULL,
    "event_token" "text",
    "event_year" smallint,
    "venue_token" "text",
    "zone_token" "text",
    "sequence_no" integer NOT NULL,
    "revision" "text" DEFAULT 'A'::"text" NOT NULL,
    "state" "public"."xpms_state" DEFAULT 'uac'::"public"."xpms_state" NOT NULL,
    "phase" "public"."xpms_atom_phase" DEFAULT 'discovery'::"public"."xpms_atom_phase" NOT NULL,
    "name" "text" NOT NULL,
    "description" "text",
    "quantity" numeric(14,4) DEFAULT 1 NOT NULL,
    "unit" "text",
    "cost_cents" bigint,
    "currency" character(3) DEFAULT 'USD'::"bpchar" NOT NULL,
    "tags" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    "payload" "jsonb" DEFAULT '{}'::"jsonb" NOT NULL,
    "uac_origin_id" "uuid",
    "lineage_root_id" "uuid",
    "owner_user_id" "uuid",
    "created_by" "uuid" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "wbs_path" "public"."ltree" GENERATED ALWAYS AS ("public"."text2ltree"("regexp_replace"((((((((((("regexp_replace"("org_token", '[^A-Za-z0-9_]'::"text", '_'::"text", 'g'::"text") || '.'::"text") || "regexp_replace"(COALESCE("event_token", '_'::"text"), '[^A-Za-z0-9_]'::"text", '_'::"text", 'g'::"text")) || '.'::"text") || "regexp_replace"(COALESCE("venue_token", '_'::"text"), '[^A-Za-z0-9_]'::"text", '_'::"text", 'g'::"text")) || '.'::"text") || "regexp_replace"(COALESCE("zone_token", '_'::"text"), '[^A-Za-z0-9_]'::"text", '_'::"text", 'g'::"text")) || '.'::"text") || ("sequence_no")::"text") || '.'::"text") || "regexp_replace"("revision", '[^A-Za-z0-9_]'::"text", '_'::"text", 'g'::"text")), '\.+'::"text", '.'::"text", 'g'::"text"))) STORED,
    CONSTRAINT "xpms_atoms_check" CHECK (((("state" = 'tpc'::"public"."xpms_state") AND ("uac_origin_id" IS NOT NULL)) OR (("state" = 'uac'::"public"."xpms_state") AND ("uac_origin_id" IS NULL))))
);


ALTER TABLE "public"."xpms_atoms" OWNER TO "postgres";


COMMENT ON TABLE "public"."xpms_atoms" IS 'XPMS · APS — atomic production unit. Every element of a production is an atom.';



COMMENT ON COLUMN "public"."xpms_atoms"."phase" IS 'Per-atom phase. Distinct enum from projects.xpms_phase to avoid LDP §SCHEMA-DONT enum reuse, even though values are identical.';



CREATE TABLE IF NOT EXISTS "public"."xpms_variance_ledger" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "org_id" "uuid" NOT NULL,
    "uac_atom_id" "uuid" NOT NULL,
    "tpc_atom_id" "uuid",
    "reason" "public"."xpms_variance_reason" NOT NULL,
    "qty_delta" numeric(14,4),
    "cost_delta_cents" bigint,
    "notes" "text",
    "recorded_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "recorded_by" "uuid" NOT NULL
);


ALTER TABLE "public"."xpms_variance_ledger" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_xpms_atom_rollup" WITH ("security_invoker"='true') AS
 SELECT "id",
    "org_id",
    "project_id",
    "identifier",
    "name",
    "phase",
    "state",
    "wbs_path",
    "public"."nlevel"("wbs_path") AS "wbs_depth",
    COALESCE("cost_cents", (0)::bigint) AS "budget_cents",
    COALESCE(( SELECT ("sum"("e"."amount_cents"))::bigint AS "sum"
           FROM "public"."expenses" "e"
          WHERE ("e"."atom_id" = "a"."id")), (0)::bigint) AS "actual_cost_cents",
    COALESCE(( SELECT ("sum"(("li"."quantity" * ("li"."unit_price_cents")::numeric)))::bigint AS "sum"
           FROM "public"."po_line_items" "li"
          WHERE ("li"."atom_id" = "a"."id")), (0)::bigint) AS "committed_cents",
    COALESCE(( SELECT ("sum"(("ii"."quantity" * ("ii"."unit_price_cents")::numeric)))::bigint AS "sum"
           FROM "public"."invoice_line_items" "ii"
          WHERE ("ii"."atom_id" = "a"."id")), (0)::bigint) AS "invoiced_cents",
    COALESCE(( SELECT ("sum"("v"."cost_delta_cents"))::bigint AS "sum"
           FROM "public"."xpms_variance_ledger" "v"
          WHERE ("v"."tpc_atom_id" = "a"."id")), (0)::bigint) AS "variance_cost_cents",
    ( SELECT ("count"(*))::integer AS "count"
           FROM "public"."xpms_variance_ledger" "v"
          WHERE ("v"."tpc_atom_id" = "a"."id")) AS "variance_count",
    ( SELECT ("count"(*))::integer AS "count"
           FROM "public"."tasks" "t"
          WHERE ("t"."xpms_atom_id" = "a"."id")) AS "task_count",
    ( SELECT ("count"(*))::integer AS "count"
           FROM "public"."tasks" "t"
          WHERE (("t"."xpms_atom_id" = "a"."id") AND ("t"."status" = 'done'::"public"."task_status"))) AS "tasks_done",
    ( SELECT ("count"(*))::integer AS "count"
           FROM "public"."deliverables" "d"
          WHERE (("d"."atom_id" = "a"."id") AND ("d"."deleted_at" IS NULL))) AS "deliverable_count",
    ( SELECT ("count"(*))::integer AS "count"
           FROM "public"."deliverables" "d"
          WHERE (("d"."atom_id" = "a"."id") AND ("d"."deleted_at" IS NULL) AND ("d"."fulfillment_state" = ANY (ARRAY['approved'::"public"."fulfillment_state", 'delivered'::"public"."fulfillment_state"])))) AS "deliverables_approved",
    ( SELECT ("count"(*))::integer AS "count"
           FROM "public"."deliverables" "d"
          WHERE (("d"."atom_id" = "a"."id") AND ("d"."deleted_at" IS NULL) AND ("d"."fulfillment_state" = ANY (ARRAY['briefed'::"public"."fulfillment_state", 'draft'::"public"."fulfillment_state", 'submitted'::"public"."fulfillment_state", 'in_review'::"public"."fulfillment_state", 'revision_requested'::"public"."fulfillment_state"])))) AS "deliverables_open",
        CASE
            WHEN (( SELECT "count"(*) AS "count"
               FROM "public"."tasks" "t"
              WHERE ("t"."xpms_atom_id" = "a"."id")) = 0) THEN NULL::numeric
            ELSE ((( SELECT "count"(*) AS "count"
               FROM "public"."tasks" "t"
              WHERE (("t"."xpms_atom_id" = "a"."id") AND ("t"."status" = 'done'::"public"."task_status"))))::numeric / (NULLIF(( SELECT "count"(*) AS "count"
               FROM "public"."tasks" "t"
              WHERE ("t"."xpms_atom_id" = "a"."id")), 0))::numeric)
        END AS "pct_complete"
   FROM "public"."xpms_atoms" "a";


ALTER VIEW "public"."v_xpms_atom_rollup" OWNER TO "postgres";


CREATE OR REPLACE VIEW "public"."v_xpms_atom_rollup_recursive" WITH ("security_invoker"='true') AS
 SELECT "parent"."id" AS "atom_id",
    "parent"."org_id",
    "parent"."project_id",
    "parent"."identifier",
    "parent"."name",
    "parent"."phase",
    "parent"."state",
    "parent"."wbs_path",
    "parent"."wbs_depth",
    ("sum"("child"."budget_cents"))::bigint AS "budget_cents_rollup",
    ("sum"("child"."actual_cost_cents"))::bigint AS "actual_cost_cents_rollup",
    ("sum"("child"."committed_cents"))::bigint AS "committed_cents_rollup",
    ("sum"("child"."invoiced_cents"))::bigint AS "invoiced_cents_rollup",
    ("sum"("child"."variance_cost_cents"))::bigint AS "variance_cost_cents_rollup",
    ("sum"("child"."variance_count"))::integer AS "variance_count_rollup",
    ("sum"("child"."task_count"))::integer AS "task_count_rollup",
    ("sum"("child"."tasks_done"))::integer AS "tasks_done_rollup",
    ("sum"("child"."deliverable_count"))::integer AS "deliverable_count_rollup",
    ("sum"("child"."deliverables_approved"))::integer AS "deliverables_approved_rollup",
    ("sum"("child"."deliverables_open"))::integer AS "deliverables_open_rollup",
    ("count"("child"."id"))::integer AS "descendant_count",
        CASE
            WHEN ("sum"("child"."budget_cents") > (0)::numeric) THEN ("sum"((COALESCE("child"."pct_complete", (0)::numeric) * ("child"."budget_cents")::numeric)) / NULLIF("sum"("child"."budget_cents"), (0)::numeric))
            WHEN ("sum"("child"."task_count") > 0) THEN (("sum"("child"."tasks_done"))::numeric / (NULLIF("sum"("child"."task_count"), 0))::numeric)
            ELSE NULL::numeric
        END AS "pct_complete_rollup"
   FROM ("public"."v_xpms_atom_rollup" "parent"
     JOIN "public"."v_xpms_atom_rollup" "child" ON ((("child"."wbs_path" OPERATOR("public".<@) "parent"."wbs_path") AND ("child"."org_id" = "parent"."org_id"))))
  GROUP BY "parent"."id", "parent"."org_id", "parent"."project_id", "parent"."identifier", "parent"."name", "parent"."phase", "parent"."state", "parent"."wbs_path", "parent"."wbs_depth";


ALTER VIEW "public"."v_xpms_atom_rollup_recursive" OWNER TO "postgres";


