    "sum"(COALESCE("a"."cost_cents", (0)::bigint)) AS "cost_cents"
   FROM ("public"."xpms_atoms" "a"
     JOIN "public"."xpms_atom_tiers" "t" ON ((("t"."atom_id" = "a"."id") AND "t"."is_primary")))
  GROUP BY "a"."org_id", "a"."project_id", "t"."tier";


